#!/usr/bin/env python3"""Script para regenerar embeddings en PostgreSQLEjecutar después de modificar la función construir_texto_embedding"""import osimport sysimport jsonimport psycopg2import psycopg2.extrasfrom sentence_transformers import SentenceTransformerfrom dotenv import load_dotenv# Cargar configuraciónload_dotenv('.env.development')# Configuración de conexiónDATABASE_URL = os.environ.get('DATABASE_URL')if not DATABASE_URL:    DATABASE_URL = "postgresql://talent_user:Talent123!@localhost:5432/talent_pipeline"def get_db_connection():    if DATABASE_URL.startswith('postgres://'):        DATABASE_URL = DATABASE_URL.replace('postgres://', 'postgresql://', 1)    return psycopg2.connect(DATABASE_URL)def construir_texto_embedding(data):    """Construye el texto completo para generar el embedding"""    texto_completo = ""        if "datos_crudos" in data:        dc = data["datos_crudos"]                # Datos básicos        texto_completo += f"""NOMBRE: {dc.get('nombre', '')}PROFESIÓN: {dc.get('profesion_escrita', '')}UBICACIÓN: {dc.get('ubicacion', '')}UNIVERSIDAD: {dc.get('universidad', '')}"""                # EXPERIENCIA LABORAL (MUY IMPORTANTE)        if dc.get('experiencia_laboral'):            texto_completo += "\nEXPERIENCIA LABORAL DETALLADA:\n"            for exp in dc.get('experiencia_laboral', []):                empresa = exp.get('empresa', '')                puesto = exp.get('puesto', '')                if empresa:                    texto_completo += f"TRABAJÓ EN: {empresa} como {puesto}\n"                    texto_completo += f"EMPRESA: {empresa}\n"                    texto_completo += f"EXPERIENCIA EN {empresa.upper()}\n"                # EMPRESAS (lista única, DUPLICADA para dar peso)        if dc.get('empresas'):            empresas_str = ', '.join(dc.get('empresas', []))            texto_completo += f"\nEMPRESAS DONDE HA TRABAJADO: {empresas_str}\n"            texto_completo += f"EMPRESA EMPRESA EMPRESA: {empresas_str}\n"            texto_completo += f"TRABAJÓ EN {empresas_str}\n"                # Experiencia texto (fallback)        if dc.get('experiencia_texto'):            texto_completo += f"\nEXPERIENCIA: {dc.get('experiencia_texto', '')}\n"                # Habilidades y herramientas        if dc.get('habilidades_listadas'):            texto_completo += f"HABILIDADES: {', '.join(dc.get('habilidades_listadas', []))}\n"        if dc.get('herramientas_listadas'):            texto_completo += f"HERRAMIENTAS: {', '.join(dc.get('herramientas_listadas', []))}\n"        if dc.get('idiomas_listados'):            texto_completo += f"IDIOMAS: {', '.join(dc.get('idiomas_listados', []))}\n"        if "interpretacion" in data:        interp = data["interpretacion"]        texto_completo += f"""SECTOR: {interp.get('sector_deducido', '')}SENIORITY: {interp.get('seniority', '')}HABILIDADES CLAVE: {', '.join(interp.get('habilidades_clave', []))}PERFIL: {interp.get('perfil_interpretado', '')}"""        return texto_completodef main():    print("🔄 Cargando modelo de embeddings...")    modelo = SentenceTransformer('all-MiniLM-L6-v2')    print("✅ Modelo cargado")        print("🔌 Conectando a PostgreSQL...")    conn = get_db_connection()    cursor = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)        # Obtener todos los candidatos    cursor.execute("SELECT id, raw_data FROM candidates ORDER BY id")    candidatos = cursor.fetchall()    print(f"📋 {len(candidatos)} candidatos encontrados")        exitos = 0    errores = 0        for c in candidatos:        try:            candidate_id = c['id']            raw_data = c['raw_data']                        if isinstance(raw_data, str):                data = json.loads(raw_data)            else:                data = raw_data                        # Construir texto            texto = construir_texto_embedding(data)                        # Generar embedding            embedding = modelo.encode(texto).tolist()                        # Guardar en PostgreSQL            cursor.execute("""                INSERT INTO candidate_embeddings (candidate_id, embedding, texto_completo, fecha_actualizacion)                VALUES (%s, %s, %s, CURRENT_TIMESTAMP)                ON CONFLICT (candidate_id) DO UPDATE SET                    embedding = EXCLUDED.embedding,                    texto_completo = EXCLUDED.texto_completo,                    fecha_actualizacion = CURRENT_TIMESTAMP            """, (candidate_id, embedding, texto))                        exitos += 1            print(f"  ✅ [{exitos}/{len(candidatos)}] Candidato ID {candidate_id} procesado")                    except Exception as e:            errores += 1            print(f"  ❌ Error con candidato ID {c['id']}: {e}")        conn.commit()    conn.close()        print(f"\n🎉 Proceso completado!")    print(f"   ✅ Exitos: {exitos}")    print(f"   ❌ Errores: {errores}")if __name__ == "__main__":    main()
